from enum import Enum
from dataclasses import dataclass, field

class Priority(Enum):
    LOW = 1
    MEDIUM = 2
    HIGH = 3
    CRITICAL = 4

@dataclass
class Task:
    id: str
    name: str
    priority: Priority
    dependencies: list[str] = field(default_factory=list)  # list of task IDs
    completed: bool = False

